import {
  Component,
  inject,
  signal,
  computed,
  TemplateRef,
  ViewChild,
  OnInit,
} from '@angular/core';
import {
  FormsModule,
  ReactiveFormsModule,
  FormBuilder,
  FormGroup,
  Validators,
} from '@angular/forms';
import { CommonModule } from '@angular/common';
import { RouterModule } from '@angular/router';
import { toSignal, toObservable } from '@angular/core/rxjs-interop';
import { catchError, of, tap, switchMap } from 'rxjs';

import { AppStoreService } from '../../services/app-store.service';
import { AppVersionService } from '../../services/app-version.service';
import { AppVersion, AppDefinition } from '../../models/app-store.models';
import { ClientDataService } from '../../../clients/services/client-data.service';
import { AppSubmissionReviewRequest } from '../../models/api/app-store-api.models';

import { ButtonModule } from 'primeng/button';
import { CardModule } from 'primeng/card';
import { DialogModule } from 'primeng/dialog';
import { TextareaModule } from 'primeng/textarea';
import { ProgressSpinnerModule } from 'primeng/progressspinner';
import { TooltipModule } from 'primeng/tooltip';
import { GridComponent } from '../../../../shared/components/grid/grid.component';
import { GridColumn } from '../../../../shared/models/grid.model';
import { AppStatusBadgeComponent } from '../../components/app-status-badge/app-status-badge.component';
import { ImgFallbackDirective } from '../../../../shared/directives/img-fallback.directive';

@Component({
  selector: 'app-admin-panel',
  imports: [
    CommonModule,
    RouterModule,
    FormsModule,
    ReactiveFormsModule,
    ButtonModule,
    CardModule,
    DialogModule,
    TextareaModule,
    ProgressSpinnerModule,
    TooltipModule,
    GridComponent,
    AppStatusBadgeComponent,
    ImgFallbackDirective,
  ],
  templateUrl: './app-admin-panel.component.html',
  styleUrls: ['./app-admin-panel.component.scss'],
})
export class AppAdminPanelComponent implements OnInit {
  private readonly appStoreService = inject(AppStoreService);
  private readonly appVersionService = inject(AppVersionService);
  private readonly clientDataService = inject(ClientDataService);
  private readonly fb = inject(FormBuilder);

  @ViewChild('appIconTemplate', { static: true })
  appIconTemplate!: TemplateRef<{ $implicit: AppVersion }>;
  @ViewChild('statusTemplate', { static: true }) statusTemplate!: TemplateRef<{
    $implicit: AppVersion;
  }>;
  @ViewChild('bumpTypeTemplate', { static: true })
  bumpTypeTemplate!: TemplateRef<{ $implicit: AppVersion }>;
  @ViewChild('actionsTemplate', { static: true })
  actionsTemplate!: TemplateRef<{ $implicit: AppVersion }>;

  // State Signals
  readonly statusFilter = signal<string>('pendingReview');
  readonly loading = signal(true);
  readonly error = signal<string | null>(null);
  private readonly refreshTrigger = signal(0);

  readonly columns = signal<GridColumn<AppVersion>[]>([]);

  private readonly versions$ = toObservable(
    computed(() => ({
      status: this.statusFilter(),
      refresh: this.refreshTrigger(),
    })),
  ).pipe(
    tap(() => {
      this.loading.set(true);
      this.error.set(null);
    }),
    switchMap(({ status }) => {
      const source$ = this.appVersionService.getAllVersions(
        status === 'ALL' ? {} : { status },
      );

      return source$.pipe(
        tap(() => this.loading.set(false)),
        catchError((err) => {
          console.error('Error loading versions:', err);
          this.loading.set(false);
          this.error.set('Unable to load versions. Please try again.');
          return of([] as AppVersion[]);
        }),
      );
    }),
  );

  readonly versions = toSignal(this.versions$, {
    initialValue: [] as AppVersion[],
  });

  readonly statusOptions: { label: string; value: string }[] = [
    { label: 'Pending Review', value: 'pendingReview' },
    { label: 'Changes Requested', value: 'changesRequested' },
    { label: 'All', value: 'ALL' },
  ];

  ngOnInit(): void {
    this.setupColumns();
  }

  private setupColumns(): void {
    this.columns.set([
      {
        field: 'name',
        header: 'App',
        sortable: true,
        cellTemplate: this.appIconTemplate,
      },
      {
        field: 'developerName',
        header: 'Developer',
        sortable: true,
      },
      {
        field: 'version',
        header: 'Version',
        sortable: true,
      },
      {
        field: 'bumpType',
        header: 'Bump Type',
        sortable: true,
        cellTemplate: this.bumpTypeTemplate,
      },
      {
        field: 'status',
        header: 'Status',
        sortable: true,
        cellTemplate: this.statusTemplate,
      },
      {
        field: 'createdDate',
        header: 'Submitted',
        sortable: true,
        valueGetter: (v) => new Date(v.createdDate).toLocaleDateString(),
      },
      {
        field: 'actions',
        header: 'Actions',
        cellTemplate: this.actionsTemplate,
      },
    ]);
  }

  onStatusFilterChange(status: string): void {
    this.statusFilter.set(status);
  }

  // Review panel state
  readonly reviewPanelVisible = signal(false);
  readonly reviewPanelVersion = signal<AppVersion | null>(null);
  readonly reviewPanelApp = signal<AppDefinition | null>(null);
  readonly reviewPanelLoading = signal(false);
  readonly isSubmittingReview = signal(false);

  readonly reviewForm: FormGroup = this.fb.group({
    comments: ['', [Validators.required, Validators.maxLength(2000)]],
    internalNotes: ['', [Validators.maxLength(2000)]],
  });

  openReviewPanel(version: AppVersion): void {
    this.reviewPanelVersion.set(version);
    this.reviewPanelApp.set(null);
    this.reviewPanelVisible.set(true);
    this.reviewPanelLoading.set(true);
    this.reviewForm.reset();
    this.appStoreService
      .getAppById(
        version.appDefinitionId,
        this.clientDataService.getSelectedClient()?.id ?? '',
      )
      .pipe(catchError(() => of(null)))
      .subscribe((app) => {
        this.reviewPanelApp.set(app);
        this.reviewPanelLoading.set(false);
      });
  }

  getFieldDiff(v: AppVersion, app: AppDefinition): Record<string, boolean> {
    const baseline = app.version.active;
    if (!baseline) {
      // First-ever submission — no prior version to compare against
      return {
        name: false,
        shortDescription: false,
        description: false,
        healthCheckUrl: false,
        iconUrl: false,
      };
    }
    return {
      name: v.name !== baseline.name,
      shortDescription: v.shortDescription !== baseline.shortDescription,
      description: v.description !== baseline.description,
      healthCheckUrl:
        (v.healthCheckUrl ?? '') !== (baseline.healthCheckUrl ?? ''),
      iconUrl: v.iconUrl !== baseline.iconUrl,
    };
  }

  submitReviewDecision(status: AppSubmissionReviewRequest['status']): void {
    const version = this.reviewPanelVersion();
    if (!version || this.reviewForm.invalid) return;
    this.isSubmittingReview.set(true);
    const { comments, internalNotes } = this.reviewForm.getRawValue() as {
      comments: string;
      internalNotes: string;
    };
    const request: AppSubmissionReviewRequest = {
      id: version.id,
      developerId: version.appDefinitionId,
      status,
      comments,
      internalNotes,
    };
    this.appStoreService.reviewApp(version.appDefinitionId, request).subscribe({
      next: () => {
        this.reviewPanelVisible.set(false);
        this.isSubmittingReview.set(false);
        this.reviewForm.reset();
        this.refreshVersions();
      },
      error: () => this.isSubmittingReview.set(false),
    });
  }

  private refreshVersions(): void {
    this.refreshTrigger.update((n) => n + 1);
  }
}
